const data = $input.first().json;

const calendlyNote = data.language === 'HR'
  ? '\n\nAko imate dodatnih pitanja ili želite razgovarati s našim nutricionistom, slobodno zakažite termin: https://calendly.com/metabelly/nutritionist-20min'
  : '\n\nIf you have further questions or would like to speak with our nutritionist, feel free to book a time: https://calendly.com/metabelly/nutritionist-20min';

const isMedical = data.category === 'MEDICAL';
let replyBody = data.auto_reply || '';

if (isMedical) {
  replyBody = data.language === 'HR'
    ? `Hvala vam na povjerenju i što ste nam se obratili.\n\nVaše pitanje zahtijeva savjet stručnjaka, stoga ćemo ga proslijediti našem nutricionistom koji će vam odgovoriti u najkraćem mogućem roku.\n\nZa brži odgovor, možete zakazati konzultaciju:${calendlyNote}`
    : `Thank you for reaching out to us.\n\nYour question requires expert advice, so we will forward it to our nutritionist who will get back to you as soon as possible.\n\nFor a faster response, you can book a consultation:${calendlyNote}`;
} else if (replyBody && !isMedical) {
  replyBody = replyBody + calendlyNote;
}

return [{ json: { ...data, finalReply: replyBody } }];

